using Ledgerly.Domain.Entities; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders; namespace Ledgerly.Infrastructure.Persistence.Configurations; public sealed class InvoiceConfiguration:IEntityTypeConfiguration<Invoice>{ public void Configure(EntityTypeBuilder<Invoice> b){ b.ToTable("invoices"); b.HasKey(i=>i.Id); b.HasMany(i=>i.Lines).WithOne().HasForeignKey(l=>l.InvoiceId).OnDelete(DeleteBehavior.Cascade); b.Navigation(i=>i.Lines).UsePropertyAccessMode(PropertyAccessMode.Field);} } public sealed class InvoiceLineConfiguration:IEntityTypeConfiguration<InvoiceLine>{ public void Configure(EntityTypeBuilder<InvoiceLine> b){ b.ToTable("invoice_lines"); b.HasKey(l=>l.Id);} }
